function populateTechniques(e,i){var t=$("#"+e);$(t).find("#ability-technique-filter").empty().append("<option disabled='disabled' selected>Choose a technique</option>");let n=$(t).find("#ability-tactic-filter").find(":selected").data("tactic"),a=[];i.forEach(function(i){i.tactic.includes(n)&&!a.includes(i.technique_id)&&(a.push(i.technique_id),appendTechniqueToList(e,n,i))})}function populateAbilities(e,i){var t=$("#"+e);let n=[],a=$(t).find("#ability-technique-filter").find(":selected").data("technique");i.forEach(function(i){i.technique_id===a&&n.push(i)}),$(t).find("#ability-ability-filter").empty().append('<option disabled="disabled" selected>'+n.length+" abilities</option>"),n.forEach(function(i){appendAbilityToList(e,i)})}function appendTechniqueToList(i,e,t){$("#"+i).find("#ability-technique-filter").append($("<option></option>").attr("value",t.technique_id).data("technique",t.technique_id).text(t.technique_id+" | "+t.technique_name))}function appendAbilityToList(i,e){$("#"+i).find("#ability-ability-filter").append($("<option></option>").attr("value",e.name).data("ability",e).text(e.name))}function searchAbilities(a,i){var e=$("#"+a),t=(e.find("#ability-technique-filter").empty().append("<option disabled='disabled' selected>All Techniques</option>"),e.find("#ability-ability-filter"));t.empty();let l=e.find("#ability-search-filter").val().toLowerCase(),d=[];l&&i.forEach(function(i){let e=!1;i.executors.forEach(function(i){null!=i.command&&i.command.toLowerCase().includes(l)&&(e=!0)});var t=i.name.toLowerCase().includes(l),n=i.description.toLowerCase().includes(l);(t||n||e)&&!d.includes(i.ability_id)&&(d.push(i.ability_id),appendAbilityToList(a,i))}),t.prepend("<option disabled='disabled' selected>"+d.length+" abilities</option>")}